var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"마, 말도 안 돼! 총알이 제대로 먹히지도 않잖아!","JPN":"あ、あり得ない！　銃が効かない！","ENG":"N-no way! Bullets don't work on it!","TWN":"這…這怎麼可能！子彈竟然無法穿透她！"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_REVELA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"자, 이제 그만 항복하세요.","JPN":"さあ、もう降伏してください。","ENG":"You should just surrender now.","TWN":"你們投降吧。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"으…… 으으으……","JPN":"う……うう……","ENG":"Aww... Aww...","TWN":"呃……呃呃……"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_REVELA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"괴, 괴물…… 넌 괴물이야!","JPN":"ば、化け物……お前は化け物だ！","ENG":"M-monster... You're a monster!","TWN":"怪…有怪物……你是怪物！！"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_REVELA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"으아아아!!!","JPN":"うわあああ！！","ENG":"Aaaah!","TWN":"啊啊啊！！"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_REVELA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"후우……","JPN":"ふぅ……","ENG":"Whew...","TWN":"呼……"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"괜찮으세요?","JPN":"大丈夫ですか？","ENG":"Are you okay?","TWN":"你們沒事吧？"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"우릴…… 도와준 건가?","JPN":"ワシらを……助けてくれたのか？","ENG":"Did you... do that to help us?","TWN":"你是……來幫我們的嗎？"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"고맙긴 하네만…… 보고도 믿기지 않는군.","JPN":"助かったが……とても信じられぬ光景じゃな。","ENG":"Thank you, but... that was unbelievable.","TWN":"雖然很感謝你……但又有點不敢置信。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"침식체가 나타나는 세상을 살아오면서, 침식체를 조종하는 인간은 한 번도 들어본 적이 없어.","JPN":"今まで侵食体が現れる世を生きてきたが、侵食体を操る人間なんて今まで一度も聞いたことがない。","ENG":"I'm used to seeing C.O.s, but I've never even heard of anyone who can command them like you.","TWN":"畢竟我活到現在，還沒看過可以控制侵蝕體的人。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"혹시 자네…… 정부에서 보내 준 카운터인가?","JPN":"もしかして君は……政府から送られたカウンターか？","ENG":"You... Are you a Counter from the government?","TWN":"還是……你是政府派來的制裁者嗎？"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"그런 건 아니지만, 여러분을 해치려는 건 아니니 믿어주세요.","JPN":"そうではないですけど、みなさんに危害を加えることはありませんので信じてください。","ENG":"No, but please trust me. I'm not here to hurt you.","TWN":"我不是，但我絕對沒有要傷害你們的意思，請相信我。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"허허…… 괜찮아. 나도 그 정도 변별력은 있다네.","JPN":"ハハハ……そのことなら大丈夫じゃ。ワシにもその程度の分別はあるんじゃよ。","ENG":"Hah hah... I know. Even I can see that.","TWN":"呵呵……放心吧！這點判斷力我還是有的。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"여러분은…… 난민 분들이신가요?","JPN":"みなさんは……難民の方ですか？","ENG":"Are you... refugees?","TWN":"你們……都是難民嗎？"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"그래, 반군을 피해 국경을 넘으려고 했지.","JPN":"ああ、反乱軍を避けて国境を越えようとしたんじゃ。","ENG":"Yes, we tried to cross the border to avoid the rebels.","TWN":"沒錯，我們原本是打算避開叛軍的耳目穿越國界的。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"요새는 반군 활동이 다시 심해져서 브로커들도 손을 뗐어.","JPN":"最近反乱軍の動きが再び活発になってきて、ブローカーたちも手を引いてな。","ENG":"Recently, they've become prevalent again so that all brokers quit.","TWN":"最近叛軍又開始四處為非作歹，掮客也關門不敢做生意。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"거기에다 우리가 살던 마을도 침식지대가 되어 버렸으니까……. 별 수 없는 거지.","JPN":"それに、ワシたちが住んでいた村も侵食地帯になってしまって……仕方がないんじゃよ。","ENG":"But we couldn't stay in our village anymore. It became Corrupted. We had no choice.","TWN":"加上我們住的地方變成了侵蝕地區……實在是無計可施啊。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"그런 일이……","JPN":"そんなことが……","ENG":"That's terrible.","TWN":"怎麼會……"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};